executeFunc((function productReviewFilter(){if(typeof formDebounce!=="function"){return false}const form=document.forms.product_review_filter_form;if(typeof form==="undefined"){return false}form.addEventListener("click",(()=>{if(idFormDebounce==lastFormDebounce){clearTimeout(lastFormDebounce)}lastFormDebounce=idFormDebounce}));const select_fields=form.querySelectorAll("select");select_fields.forEach((field=>field.addEventListener("change",formDebounce((()=>{form.submit()}),1500))));return true}));